UPDATE employee
SET dept_id = #{deptId}
WHERE emp_id = #{empId}

mapper.select:
/* 1. 부서 정보 추출 */ SELECT 'DEPT_' || dept_id AS id, CASE WHEN parent_dept_id IS NULL THEN '#' ELSE 'DEPT_' || parent_dept_id END AS parent, dept_name AS text, 'jstree-folder' AS icon, 1 AS sort_priority FROM department
UNION ALL
/* 2. 직원 정보 추출 */ SELECT 'EMP_' || emp_id AS id, 'DEPT_' || dept_id AS parent, emp_name || ' ' AS text, 'jstree-file' AS icon, 0 AS sort_priority FROM employee
ORDER BY sort_priority ASC, text ASC
